import{_ as e,o as t,c as s,ag as n}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Earnings","description":"Run the numbers before you commit hardware.","frontmatter":{"description":"Run the numbers before you commit hardware."},"headers":[],"relativePath":"provers/earnings.md","filePath":"provers/earnings.md","lastUpdated":1777130260000}'),i={name:"provers/earnings.md"};function r(o,a,l,p,c,d){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="earnings" tabindex="-1">Earnings <a class="header-anchor" href="#earnings" aria-label="Permalink to &quot;Earnings&quot;">​</a></h1><p>Calculate your monthly revenue, fees, and net margin from running a Prova prover.</p><h2 id="try-the-live-calculator" tabindex="-1">Try the live calculator <a class="header-anchor" href="#try-the-live-calculator" aria-label="Permalink to &quot;Try the live calculator&quot;">​</a></h2><p><a href="https://prova.network/#earn" target="_blank" rel="noreferrer">prova.network/#earn</a> has the interactive version with sliders. The math below is the same model.</p><h2 id="formula" tabindex="-1">Formula <a class="header-anchor" href="#formula" aria-label="Permalink to &quot;Formula&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gross monthly = capacity_TiB × utilization × price_per_TiB_month</span></span>
<span class="line"><span>fees          = gross × 0.01           # protocol fee</span></span>
<span class="line"><span>drag          = gross × (1 − uptime)   # missed proofs</span></span>
<span class="line"><span>net monthly   = gross − fees − drag</span></span></code></pre></div><ul><li><code>capacity_TiB</code> — your committed capacity in TiB (TB × 0.9094)</li><li><code>utilization</code> — fraction of your capacity that&#39;s actually under contract (0.7–0.9 in practice)</li><li><code>price_per_TiB_month</code> — what you advertise; the marketplace clears at ~75% of advertised</li><li><code>uptime</code> — fraction of proofs you successfully posted (target ≥ 99.5%)</li></ul><h2 id="worked-example" tabindex="-1">Worked example <a class="header-anchor" href="#worked-example" aria-label="Permalink to &quot;Worked example&quot;">​</a></h2><p>A 20 TB prover at 75% utilization, $4/TiB-month, 99.5% uptime:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>capacity   = 20 × 0.9094 = 18.19 TiB</span></span>
<span class="line"><span>active     = 18.19 × 0.75 = 13.64 TiB</span></span>
<span class="line"><span>gross      = 13.64 × $4.00 = $54.56 / month</span></span>
<span class="line"><span>fee (1%)   = $0.55</span></span>
<span class="line"><span>drag       = $0.27</span></span>
<span class="line"><span>net        = $53.74 / month</span></span>
<span class="line"><span>annualized = $644 / year</span></span></code></pre></div><p>For a 100 TB prover, multiply by 5:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gross      = $272.80 / month</span></span>
<span class="line"><span>net        = $268.70 / month</span></span>
<span class="line"><span>annualized = $3,224 / year</span></span></code></pre></div><p>For a 1 PB cluster:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gross      = $2,728 / month</span></span>
<span class="line"><span>net        = $2,687 / month</span></span>
<span class="line"><span>annualized = $32,244 / year</span></span></code></pre></div><h2 id="break-even" tabindex="-1">Break-even <a class="header-anchor" href="#break-even" aria-label="Permalink to &quot;Break-even&quot;">​</a></h2><p>Hardware capex on a Hetzner AX41 (10 TB SSD) is ~$50/month rent. Net at $4/TiB-month and 75% utilization breaks even at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>50 / (4 × 0.9094 × 0.75 × 0.99 × 0.99) = ~18.6 TiB</span></span></code></pre></div><p>So a 20 TB prover at the default parameters is <strong>just above break-even</strong> at $4/TiB-month. Push price up to $6 or utilization up to 90% and margins improve quickly.</p><h2 id="pricing-strategy" tabindex="-1">Pricing strategy <a class="header-anchor" href="#pricing-strategy" aria-label="Permalink to &quot;Pricing strategy&quot;">​</a></h2><p>You set the advertised price. The marketplace doesn&#39;t enforce a single price — clients pick provers based on price + reputation + region. Three positions:</p><ul><li><strong>Cold / archive:</strong> $1-2 / TiB-month. High utilization, low margin per byte.</li><li><strong>Default:</strong> $3-5 / TiB-month. Most clients. Sweet spot.</li><li><strong>Premium / SLA:</strong> $6-10 / TiB-month. Constrained regions, high reputation, fast retrieval, white-glove ops.</li></ul><p>Beyond ~$10, you&#39;re competing with S3 and need a reason — usually compliance (data sovereignty, audit trails).</p><h2 id="slash-risk" tabindex="-1">Slash risk <a class="header-anchor" href="#slash-risk" aria-label="Permalink to &quot;Slash risk&quot;">​</a></h2><p>Worst case: 100% of stake gets slashed. For a 10 TB prover with $500 staked, that&#39;s a $500 hit on top of lost revenue. Conservative slash schedule:</p><table tabindex="0"><thead><tr><th>Failure</th><th>Slash</th></tr></thead><tbody><tr><td>Single missed proof</td><td>0% (warning)</td></tr><tr><td>3 consecutive misses</td><td>5%</td></tr><tr><td>Sustained failure</td><td>25%</td></tr><tr><td>Provable deletion</td><td>100% + ban</td></tr></tbody></table><p>Most operators see 0% slashing if they:</p><ul><li>Run on a UPS</li><li>Monitor proof success rate (alert below 99%)</li><li>Use ZFS / btrfs with monthly scrubs</li><li>Plan maintenance windows during low-deal-count periods</li></ul><h2 id="tax-treatment" tabindex="-1">Tax treatment <a class="header-anchor" href="#tax-treatment" aria-label="Permalink to &quot;Tax treatment&quot;">​</a></h2><p>Storage revenue is ordinary income in most jurisdictions. Slashed stake might be treated as a capital loss or a cost-of-doing-business expense — talk to a real accountant. The on-chain ledger gives you a complete audit trail.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./hardware">Hardware</a></li><li><a href="./become-a-prover">Become a prover</a></li></ul>`,31)])])}const m=e(i,[["render",r]]);export{u as __pageData,m as default};
